import jwt
import base64
import json

def decode(token):
    # Decode the token
    decoded = jwt.decode(token, verify=False)

    # Get the header and payload
    header = decoded['header']
    payload = decoded['payload']

    # Print the header and payload in JSON format
    print('Header:')
    print(json.dumps(header))
    print()
    print('Payload:')
    print(json.dumps(payload))

def verify(token):
    # Verify the token using the public key
    try:
        jwt.decode(token, verify=False)

        # Print a success message if verification is successful
        print('Token verified!')

    except Exception as e:
        # Print an error message if verification fails
        print('Error:', str(e))

def main():
    token = '<KEY>'

    decode(token)
    verify(token)


if __name__ == '__main__':
    main()